_font_tmp_files = []

def _load_font(b64_data: str) -> bool:
    """Decode a base64 TTF, write to a temp file, register with macOS CoreText."""
    try:
        font_bytes = _base64.b64decode(b64_data)
        tmp = _tempfile.NamedTemporaryFile(suffix=".ttf", delete=False)
        tmp.write(font_bytes)
        tmp.close()
        _font_tmp_files.append(tmp.name)

        ct = _ctypes.cdll.LoadLibrary(_cutil.find_library("CoreText"))
        cf = _ctypes.cdll.LoadLibrary(_cutil.find_library("CoreFoundation"))

        cf.CFURLCreateFromFileSystemRepresentation.restype = _ctypes.c_void_p
        cf.CFURLCreateFromFileSystemRepresentation.argtypes = [
            _ctypes.c_void_p, _ctypes.c_char_p, _ctypes.c_long, _ctypes.c_bool
        ]
        ct.CTFontManagerRegisterFontsForURL.argtypes = [
            _ctypes.c_void_p, _ctypes.c_uint32, _ctypes.c_void_p
        ]
        ct.CTFontManagerRegisterFontsForURL.restype = _ctypes.c_bool

        url = cf.CFURLCreateFromFileSystemRepresentation(
            None, tmp.name.encode("utf-8"), len(tmp.name), False
        )
        ct.CTFontManagerRegisterFontsForURL(url, 1, None)  # scope=process
        return True
    except Exception as e:
        print(f"Font load warning: {e}")
        return False

def _cleanup_fonts():
    for path in _font_tmp_files:
        try: _os.unlink(path)
        except: pass

_atexit.register(_cleanup_fonts)
_fonts_loaded = _load_font(_FONT_REGULAR_B64) and _load_font(_FONT_BOLD_B64)

# Font family name to use — falls back to Menlo if registration failed
_SS = "Source Sans 3" if _fonts_loaded else "Menlo"

from pathlib import Path


# ---------------------------------------------------------------------------
# Colours & fonts — dark utilitarian theme with amber accents
# ---------------------------------------------------------------------------
BG          = "#1a1a1a"
BG_PANEL    = "#242424"
BG_INPUT    = "#2e2e2e"
FG          = "#e8e8e8"
FG_DIM      = "#888888"
ACCENT      = "#e8a030"       # amber
ACCENT_DIM  = "#a06818"
SUCCESS     = "#50c878"
ERROR       = "#e85040"
FONT_BODY   = (_SS, 13)
FONT_LABEL  = (_SS, 11)
FONT_TITLE  = (_SS, 20, "bold")
FONT_LOG    = (_SS, 11)
RADIUS      = 6


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def styled_entry(parent, **kw) -> tk.Entry:
    e = tk.Entry(
        parent,
        bg=BG_INPUT, fg=FG,
        insertbackground=ACCENT,
        relief="flat",
        font=FONT_BODY,
        highlightthickness=1,
        highlightcolor=ACCENT,
        highlightbackground=BG_PANEL,
        **kw,
    )
    return e


def styled_label(parent, text, dim=False, **kw) -> tk.Label:
    return tk.Label(
        parent,
        text=text,
        bg=BG_PANEL,
        fg=FG_DIM if dim else FG,
        font=FONT_LABEL,
        anchor="w",
        **kw,
    )


def field_row(parent, label: str, row: int) -> tk.Entry:
    """Create a labelled entry row and return the Entry widget."""
    styled_label(parent, label).grid(row=row, column=0, sticky="w", padx=(0, 12), pady=(6, 2))
    entry = styled_entry(parent)
    entry.grid(row=row, column=1, sticky="ew", pady=(6, 2))
    return entry


# ---------------------------------------------------------------------------
# Main application
# ---------------------------------------------------------------------------

class App(tk.Tk):
    def __init__(self):
        super().__init__()

        self.title("mac-pdf-rgb-fix")
        self.configure(bg=BG)
        self.resizable(True, True)
        self.minsize(780, 860)

        # Centre on screen
        self.update_idletasks()
        w, h = 820, 920
        x = (self.winfo_screenwidth()  - w) // 2
        y = (self.winfo_screenheight() - h) // 2
        self.geometry(f"{w}x{h}+{x}+{y}")

        self._build_ui()

    # -----------------------------------------------------------------------
    # UI construction
    # -----------------------------------------------------------------------

    def _build_ui(self):
        # ── Title bar ──────────────────────────────────────────────────────
        title_bar = tk.Frame(self, bg=BG, pady=18)
        title_bar.pack(fill="x", padx=28)

        tk.Label(
            title_bar,
            text="mac-pdf-rgb-fix",
            bg=BG, fg=ACCENT,
            font=FONT_TITLE,
            anchor="w",
        ).pack(side="left")

        tk.Label(
            title_bar,
            text="Apple-compatible PDF image converter",
            bg=BG, fg=FG_DIM,
            font=FONT_LABEL,
            anchor="e",
        ).pack(side="right", padx=(0, 2))

        # ── Main panel ─────────────────────────────────────────────────────
        panel = tk.Frame(self, bg=BG_PANEL, bd=0)
        panel.pack(fill="both", expand=True, padx=20, pady=(0, 20))
        panel.columnconfigure(0, weight=1)

        # ── File section ───────────────────────────────────────────────────
        self._section(panel, "FILES", 0)

        file_frame = tk.Frame(panel, bg=BG_PANEL)
        file_frame.grid(row=1, column=0, sticky="ew", padx=20, pady=(0, 8))
        file_frame.columnconfigure(1, weight=1)

        # Input
        styled_label(file_frame, "Input PDF").grid(
            row=0, column=0, sticky="w", padx=(0, 12), pady=(6, 2))
        self.input_var = tk.StringVar()
        inp = styled_entry(file_frame, textvariable=self.input_var)
        inp.grid(row=0, column=1, sticky="ew", pady=(6, 2))
        self.input_var.trace_add("write", self._on_input_changed)

        tk.Button(
            file_frame, text="Browse…",
            bg=ACCENT_DIM, fg=FG, activebackground=ACCENT, activeforeground=BG,
            relief="flat", font=FONT_LABEL, cursor="hand2",
            command=self._browse_input, padx=10,
        ).grid(row=0, column=2, padx=(8, 0), pady=(6, 2))

        # Output
        styled_label(file_frame, "Output PDF").grid(
            row=1, column=0, sticky="w", padx=(0, 12), pady=(6, 2))
        self.output_var = tk.StringVar()
        styled_entry(file_frame, textvariable=self.output_var).grid(
            row=1, column=1, sticky="ew", pady=(6, 2))

        tk.Button(
            file_frame, text="Browse…",
            bg=ACCENT_DIM, fg=FG, activebackground=ACCENT, activeforeground=BG,
            relief="flat", font=FONT_LABEL, cursor="hand2",
            command=self._browse_output, padx=10,
        ).grid(row=1, column=2, padx=(8, 0), pady=(6, 2))

        # ── Quality section ────────────────────────────────────────────────
        self._section(panel, "JPEG QUALITY", 2)

        q_frame = tk.Frame(panel, bg=BG_PANEL)
        q_frame.grid(row=3, column=0, sticky="ew", padx=20, pady=(0, 8))
        q_frame.columnconfigure(1, weight=1)

        self.quality_var = tk.IntVar(value=95)

        # Quality value label (e.g. "95")
        self.quality_label = styled_label(q_frame, "95", dim=False)
        self.quality_label.config(fg=ACCENT, width=4, font=FONT_BODY)
        self.quality_label.grid(row=0, column=0, sticky="w", padx=(0, 12))

        # Custom canvas slider with filled track
        self._slider_canvas = tk.Canvas(
            q_frame, height=28, bg=BG_PANEL,
            highlightthickness=0, cursor="hand2",
        )
        self._slider_canvas.grid(row=0, column=1, sticky="ew", pady=4)
        self._slider_canvas.bind("<Configure>",      self._draw_slider)
        self._slider_canvas.bind("<Button-1>",       self._slider_click)
        self._slider_canvas.bind("<B1-Motion>",      self._slider_click)
        self._slider_canvas.bind("<MouseWheel>",     self._slider_scroll)

        # Min / max tick labels
        tk.Label(q_frame, text="1", bg=BG_PANEL, fg=FG_DIM,
                 font=(_SS, 9)).grid(row=1, column=1, sticky="w")
        tk.Label(q_frame, text="95", bg=BG_PANEL, fg=FG_DIM,
                 font=(_SS, 9)).grid(row=1, column=1, sticky="e")

        styled_label(q_frame, "Higher = better quality, larger file", dim=True).grid(
            row=0, column=2, padx=(12, 0))

        # ── Metadata section ───────────────────────────────────────────────
        self._section(panel, "PDF METADATA", 4)

        meta_frame = tk.Frame(panel, bg=BG_PANEL)
        meta_frame.grid(row=5, column=0, sticky="ew", padx=20, pady=(0, 8))
        meta_frame.columnconfigure(1, weight=1)

        self.e_title    = field_row(meta_frame, "Title",    0)
        self.e_author   = field_row(meta_frame, "Author",   1)
        self.e_subject  = field_row(meta_frame, "Subject",  2)
        self.e_keywords = field_row(meta_frame, "Keywords", 3)

        styled_label(meta_frame, "(press Enter to keep existing values)", dim=True).grid(
            row=4, column=0, columnspan=2, sticky="w", pady=(4, 0))

        # ── Convert button ─────────────────────────────────────────────────
        self._section(panel, "CONVERT", 6)

        btn_frame = tk.Frame(panel, bg=BG_PANEL)
        btn_frame.grid(row=7, column=0, sticky="ew", padx=20, pady=(0, 12))

        self.convert_btn = tk.Button(
            btn_frame,
            text="Convert PDF",
            bg=ACCENT, fg=BG,
            activebackground=ACCENT_DIM, activeforeground=FG,
            relief="flat",
            font=(_SS, 14, "bold"),
            cursor="hand2",
            command=self._start_conversion,
            pady=10,
        )
        self.convert_btn.pack(fill="x")

        # ── Log section ────────────────────────────────────────────────────
        self._section(panel, "LOG", 8)

        log_frame = tk.Frame(panel, bg=BG_PANEL)
        log_frame.grid(row=9, column=0, sticky="nsew", padx=20, pady=(0, 20))
        log_frame.columnconfigure(0, weight=1)
        log_frame.rowconfigure(0, weight=1)
        panel.rowconfigure(9, weight=1)

        self.log = scrolledtext.ScrolledText(
            log_frame,
            bg=BG_INPUT, fg=FG,
            font=FONT_LOG,
            relief="flat",
            state="disabled",
            wrap="word",
            height=5,
            insertbackground=ACCENT,
        )
        self.log.pack(fill="both", expand=True)
        self.log.tag_config("success", foreground=SUCCESS)
        self.log.tag_config("error",   foreground=ERROR)
        self.log.tag_config("accent",  foreground=ACCENT)
        self.log.tag_config("dim",     foreground=FG_DIM)

    def _section(self, parent, title: str, row: int):
        """Render a section header rule."""
        f = tk.Frame(parent, bg=BG_PANEL)
        f.grid(row=row, column=0, sticky="ew", padx=20, pady=(16, 4))
        f.columnconfigure(1, weight=1)
        tk.Label(f, text=title, bg=BG_PANEL, fg=ACCENT,
                 font=(_SS, 10, "bold")).grid(row=0, column=0, padx=(0, 8))
        tk.Frame(f, bg=ACCENT_DIM, height=1).grid(row=0, column=1, sticky="ew")

    # -----------------------------------------------------------------------
    # Event handlers
    # -----------------------------------------------------------------------

    def _browse_input(self):
        path = filedialog.askopenfilename(
            title="Select PDF",
            filetypes=[("PDF files", "*.pdf"), ("All files", "*.*")],
        )
        if path:
            self.input_var.set(path)

    def _browse_output(self):
        path = filedialog.asksaveasfilename(
            title="Save output PDF as",
            defaultextension=".pdf",
            filetypes=[("PDF files", "*.pdf")],
        )
        if path:
            self._output_manually_set = True
            self.output_var.set(path)

    def _on_input_changed(self, *_):
        """Auto-populate output path when input is selected.
        Always regenerates the output path from the new input unless the user
        has manually chosen an output via the Browse button."""
        inp = self.input_var.get()
        if inp and not getattr(self, "_output_manually_set", False):
            p = Path(inp)
            self.output_var.set(str(p.with_stem(p.stem + "_rgb")))

        # Pre-fill metadata from existing PDF
        if inp and Path(inp).exists():
            try:
                import fitz
                doc = fitz.open(inp)
                meta = doc.metadata
                doc.close()
                for entry, key in [
                    (self.e_title,    "title"),
                    (self.e_author,   "author"),
                    (self.e_subject,  "subject"),
                    (self.e_keywords, "keywords"),
                ]:
                    entry.delete(0, "end")
                    if meta.get(key):
                        entry.insert(0, meta[key])
            except Exception as e:
                self._log(f"Warning: could not read metadata from PDF — {e}\n", "error")

    def _on_quality_changed(self, val=None):
        """Update the quality label and redraw the custom slider track."""
        self.quality_label.config(text=str(self.quality_var.get()))
        self._draw_slider()

    def _draw_slider(self, event=None):
        """Draw the custom slider: dark trough, filled amber track, thumb circle."""
        c = self._slider_canvas
        c.delete("all")
        w = c.winfo_width()
        h = c.winfo_height()
        if w < 10:
            return

        PAD    = 10   # horizontal padding so thumb doesn't clip edges
        cy     = h // 2
        radius = 7    # thumb radius
        track_h = 4   # track height

        # Fraction of the way along (0.0 – 1.0)
        frac = (self.quality_var.get() - 1) / (95 - 1)
        fill_x = PAD + frac * (w - 2 * PAD)

        # Unfilled (dark) portion of track
        c.create_rectangle(
            PAD, cy - track_h // 2,
            w - PAD, cy + track_h // 2,
            fill=BG_INPUT, outline="", tags="track"
        )
        # Filled (amber) portion of track
        if fill_x > PAD:
            c.create_rectangle(
                PAD, cy - track_h // 2,
                fill_x, cy + track_h // 2,
                fill=ACCENT, outline="", tags="fill"
            )
        # Thumb circle
        c.create_oval(
            fill_x - radius, cy - radius,
            fill_x + radius, cy + radius,
            fill=ACCENT, outline=BG, width=2, tags="thumb"
        )

    def _slider_click(self, event):
        """Handle click or drag on the slider canvas."""
        c = self._slider_canvas
        w = c.winfo_width()
        PAD = 10
        frac = max(0.0, min(1.0, (event.x - PAD) / (w - 2 * PAD)))
        val = round(1 + frac * (95 - 1))
        self.quality_var.set(val)
        self._on_quality_changed()

    def _slider_scroll(self, event):
        """Mouse wheel nudges the quality value by 1."""
        delta = -1 if event.delta < 0 else 1
        val = max(1, min(95, self.quality_var.get() + delta))
        self.quality_var.set(val)
        self._on_quality_changed()

    # -----------------------------------------------------------------------
    # Conversion
    # -----------------------------------------------------------------------

    def _start_conversion(self):
        input_path  = self.input_var.get().strip()
        output_path = self.output_var.get().strip()

        if not input_path:
            messagebox.showerror("Error", "Please select an input PDF.")
            return
        if not Path(input_path).exists():
            messagebox.showerror("Error", f"Input file not found:\n{input_path}")
            return
        if not output_path:
            messagebox.showerror("Error", "Please specify an output path.")
            return

        self.convert_btn.config(state="disabled", text="Converting…")
        self._log_clear()
        self._log(f"Input:   {input_path}\n", "dim")
        self._log(f"Output:  {output_path}\n", "dim")
        self._log(f"Quality: {self.quality_var.get()}\n\n", "dim")

        metadata = {
            "title":    self.e_title.get().strip(),
            "author":   self.e_author.get().strip(),
            "subject":  self.e_subject.get().strip(),
            "keywords": self.e_keywords.get().strip(),
        }

        # Run conversion in a background thread so the UI stays responsive
        t = threading.Thread(
            target=self._run_conversion,
            args=(input_path, output_path, self.quality_var.get(), metadata),
            daemon=True,
        )
        t.start()

    def _run_conversion(self, input_path, output_path, quality, metadata):
        """Called in a background thread."""
        try:
            # Redirect stdout so process_pdf's print() calls appear in the log
            old_stdout = sys.stdout
            sys.stdout = _LogWriter(self._log_line)

            # Import and call the core processing function directly
            sys.path.insert(0, str(Path(__file__).parent))
            from pdf_images_to_rgb import process_pdf_with_metadata
            process_pdf_with_metadata(input_path, output_path, quality, metadata)

            sys.stdout = old_stdout
            self.after(0, self._on_success, output_path)
        except Exception as e:
            sys.stdout = old_stdout
            self.after(0, self._on_error, str(e))

    def _on_success(self, output_path):
        self._log(f"\n✓ Saved to {output_path}", "success")
        self.convert_btn.config(state="normal", text="Convert PDF")
        messagebox.showinfo("Done", f"Conversion complete!\n\n{output_path}")

    def _on_error(self, msg):
        self._log(f"\n✗ Error: {msg}", "error")
        self.convert_btn.config(state="normal", text="Convert PDF")
        messagebox.showerror("Conversion failed", msg)

    # -----------------------------------------------------------------------
    # Log helpers
    # -----------------------------------------------------------------------

    def _log(self, text: str, tag: str = ""):
        self.log.config(state="normal")
        self.log.insert("end", text, tag)
        self.log.see("end")
        self.log.config(state="disabled")

    def _log_line(self, text: str):
        """Called from the LogWriter on the main thread."""
        self.after(0, self._log, text)

    def _log_clear(self):
        self.log.config(state="normal")
        self.log.delete("1.0", "end")
        self.log.config(state="disabled")


class _LogWriter(io.TextIOBase):
    """Redirects stdout writes to a callback, line by line."""
    def __init__(self, callback):
        self._cb = callback
        self._buf = ""

    def write(self, s: str) -> int:
        self._buf += s
        while "\n" in self._buf:
            line, self._buf = self._buf.split("\n", 1)
            self._cb(line + "\n")
        return len(s)

    def flush(self):
        if self._buf:
            self._cb(self._buf)
            self._buf = ""


# ---------------------------------------------------------------------------
# Entry point
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    app = App()
    app.mainloop()